INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2201, 211321, 12, 107, '[转贴][转帖]打偏了', '有一天，一个神父和一个修女，一起打高尔夫。 
<br>
<br>神父打了一杆，没进。 
<br>
<br>神父说：TMD，打偏了。 
<br>
<br>修女有点不高兴，说：我们身为神职人员，你说脏话，上帝会不高兴的。 
<br>
<br>这个时候，天上的太阳突然不见了，飘过来一大团棉花糖。 
<br>
<br>神父不作声，又打了一杆，球又没进洞。 
<br>
<br>神父说：TMD，打偏了。 
<br>
<br>修女说：你居然又说!上帝会生气的! 
<br>
<br>这个时候，天上居然下起了雨。 
<br>
<br>神父再打了一杆，还是没进。 
<br>
<br>神父说：TMD，打偏了。 
<br>
<br>修女暴跳如雷，大叫：上帝是不会原谅你的! 
<br>
<br>话未落音，一个闪电辟下来，当场把修女辟S了。 
<br>
<br>神父茫然四顾，然后听到一个沉闷的声音从云层里传来：TMD，打偏了。', '有一天，一个神父和一个修女，一起打高尔夫。

神父打了一杆，没进。

神父说：TMD，打偏了。

修女有点不高兴，说：我们身为神职人员，你说脏话，上帝会不高兴的。

这个时候，天上的太阳突然不见了，飘过来一大团棉花糖。

神父不作声，又打了一杆，球又没进洞。

神父说：TMD，打偏了。

修女说：你居然又说!上帝会生气的!

这个时候，天上居然下起了雨。

神父再打了一杆，还是没进。

神父说：TMD，打偏了。

修女暴跳如雷，大叫：上帝是不会原谅你的!

话未落音，一个闪电辟下来，当场把修女辟S了。

神父茫然四顾，然后听到一个沉闷的声音从云层里传来：TMD，打偏了。', '把你的回忆风干，撒上盐，等你老了的时候用来下酒！



